# Path: src/velm/codex/atoms/monitor.py# -------------------------------------"""=================================================================================== THE OBSERVABILITY SENTRY (V-Ω-MONITOR-DOMAIN)                               ===================================================================================LIF: 50,000,000,000 | ROLE: VISIBILITY_ENGINEERGenerates dashboards and alert configurations.================================================================================="""from textwrap import dedentfrom typing import Dict, Anyfrom ..contract import BaseDirectiveDomainfrom ..loader import domain@domain("monitor")class MonitorDomain(BaseDirectiveDomain):    """The Eye that Never Sleeps."""    @property    def namespace(self) -> str: return "monitor"    def help(self) -> str: return "Generates Grafana dashboards and Prometheus alerts."    def _directive_grafana_dashboard(self, context: Dict[str, Any], title: str, panels: str = "cpu,memory") -> str:        """        monitor.grafana_dashboard(title="API Vitals")        Returns a JSON structure for a Grafana dashboard.        """        # Simplified JSON construction        return f"""        {{            "title": "{title}",            "panels": [                {{                    "type": "graph",                    "title": "CPU Usage",                    "targets": [{{"expr": "rate(container_cpu_usage_seconds_total[1m])"}}]                }},                {{                    "type": "graph",                    "title": "Memory Usage",                    "targets": [{{"expr": "container_memory_usage_bytes"}}]                }}            ],            "schemaVersion": 16        }}        """    def _directive_prometheus_config(self, context: Dict[str, Any], targets: str = "localhost:8000") -> str:        target_list = [f"'{t}'" for t in targets.split(',')]        return dedent(f"""            global:              scrape_interval: 15s            scrape_configs:              - job_name: 'velm_services'                static_configs:                  - targets: [{', '.join(target_list)}]        """).strip()